);

  // suppress errors
  logic                unused_1;
  logic [PktW-1:0]     unused_2;
  assign unused_1 = in_ep_rollback_i;
  assign unused_2 = in_ep_get_addr_i;

  import usb_consts_pkg::*;

  // State machine for control transfers
  typedef enum logic [2:0] {
    StIdle      = 3'h0,
    StSetup     = 3'h1,
    StDataIn    = 3'h2,
