  usbdev_endpoint_setup(ctx, ep, 1, ssctx, NULL, ss_rx, ss_flush);
  ssctx->ctx = ctx;
  ssctx->ep = ep;
  ssctx->got_byte = got_byte;
  ssctx->cur_buf = -1;
}

